    rt_kprintf("\t%s\n", (regs->sstatus & SSTATUS_SPP)
                             ? "Last Privilege is Supervisor Mode"
                             : "Last Privilege is User Mode");
    rt_kprintf("\t%s\n", (regs->sstatus & SSTATUS_SUM)
                             ? "Permit to Access User Page"
